import logging
from logging.handlers import RotatingFileHandler
import os

# Set up basic configuration
logging.basicConfig(level=logging.INFO)

# Define the handler to store logs in a rotating log file
rotator = RotatingFileHandler('/var/log/myapp.log', maxBytes=10*1024*1024, backupCount=5)

# Create a formatter and attach it to the rotator
formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
rotator.setFormatter(formatter)

# Get the logger object
logger = logging.getLogger()

# Add the rotator to the logger
logger.addHandler(rotator)

try:
    # Set file permissions for log files
    os.chmod('/var/log/myapp.log', 0o600)
except Exception as e:
    print(f"Error setting file permissions: {e}")

# Test the logger by logging some messages
logger.info('This is an info message')
logger.warning('This is a warning message')
logger.error('This is an error message')